module top_module(
    input clk,
    input rst,
    input [31:0] in,
    input in_valid,
    output reg [31:0] out,
    output reg out_valid
);reg [31:0] total;
reg [31:0] count;

always @(posedge clk) begin
    if (rst) begin
        total <= 0;
        count <= 0;
        out_valid <= 0;
    end else if (in_valid) begin
        total <= total + in;
        count <= count + 1;
    end else if (count > 0) begin
        out <= total;
        out_valid <= 1;
        total <= 0;
        count <= 0;
    end else begin
        out_valid <= 0;
    end
end

endmodule
